sql:
SELECT COUNT(*)
  FROM time_periods
  WHERE period_type = 'year';

SELECT device_type_id, AVG(device_count) AS avg_device_count
FROM device_usage_by_type
WHERE device_type_id = 1;

SELECT AVG(mobile_percentage) AS avg_mobile_usage
FROM device_usage
WHERE mobile_percentage > 0;

SELECT AVG(all_devices_percentage) AS avg_all_devices_percentage
FROM device_usage
WHERE last_updated > '2023-05-01';

SELECT country_id, SUM(all_devices_count) AS total_devices
FROM device_usage
GROUP BY country_id;

external_knowledge:
- Device types refer to categories such as desktop and mobile; 
- Time periods can be months, quarters, or years; 
- The root time period is the highest level in the time period hierarchy; 
- The growth rate is a measure of how device usage changes over time; 
- Average session time is the mean duration of time devices are used during a session; 
- Cumulative device count is the running total of all devices used over time for each usage ID.

sql:
SELECT AVG(STRFTIME('%s', average_session_time)) AS average_session_time_seconds
FROM device_usage_by_type
WHERE device_type_id = 1;

SELECT usage_id, average_session_time
FROM device_usage_by_type
WHERE device_type_id = 2;

SELECT last_updated
FROM device_usage
WHERE usage_id = 1;
